import React from 'react';

const JumpToTopBtn = () => {

  const jumpToTop = () => {
    console.log('click!');
    window.scrollTo({
      top: 0,
      behavior: 'smooth'
    });
  }

  return <a className='jump-to-top-btn' onClick={jumpToTop}>
    <i aria-label="scroll to top of page" className="fas fa-chevron-up"></i>
  </a>;
};

export default JumpToTopBtn;
